firmware_template.source:
#include "lsm9ds1.h"
#include <Wire.h>
#include <Adafruit_LSM9DS1.h>
#include <Adafruit_Sensor.h>
static Adafruit_LSM9DS1 lsm;
static float _ax=0,_ay=0,_az=0,_gx=0,_gy=0,_gz=0,_mx=0,_my=0,_mz=0;static unsigned long _l=0;
void lsm9ds1_setup(){Wire.begin();if(!lsm.begin()){Serial.println("[lsm9ds1] Fail!");return;}lsm.setupAccel(lsm.LSM9DS1_ACCELRANGE_2G);lsm.setupMag(lsm.LSM9DS1_MAGGAIN_4GAUSS);lsm.setupGyro(lsm.LSM9DS1_GYROSCALE_245DPS);Serial.println("[lsm9ds1] OK 9DOF");}
void lsm9ds1_loop(){if(millis()-_l<50)return;_l=millis();lsm.read();sensors_event_t a,m,g,t;lsm.getEvent(&a,&m,&g,&t);_ax=a.acceleration.x;_ay=a.acceleration.y;_az=a.acceleration.z;_gx=g.gyro.x;_gy=g.gyro.y;_gz=g.gyro.z;_mx=m.magnetic.x;_my=m.magnetic.y;_mz=m.magnetic.z;}
float lsm9ds1_accel_x(){return _ax;}
float lsm9ds1_accel_y(){return _ay;}
float lsm9ds1_accel_z(){return _az;}
float lsm9ds1_gyro_x(){return _gx;}
float lsm9ds1_gyro_y(){return _gy;}
float lsm9ds1_gyro_z(){return _gz;}
float lsm9ds1_mag_x(){return _mx;}
float lsm9ds1_mag_y(){return _my;}
float lsm9ds1_mag_z(){return _mz;}
